import { useEffect, useState } from "react";
import GlobalStyle from "./assets/styles/GlobalStyle";

import PublicWebsite from "./pages/Public";
import LoginPage from "./pages/Auth/LoginPage";
import StudentDashboard from "./pages/Student";
import AdminDashboard from "./pages/Admin";
import { TeacherDashboard, ParentDashboard } from "./pages/TeacherParent";
import { AdminProfileProvider } from "./context/AdminProfileContext";
import { StudentProfileProvider } from "./context/StudentProfileContext";

export default function App() {
  const [auth, setAuth] = useState(null);
  const [view, setView] = useState("public");

  useEffect(() => {
    const raw = localStorage.getItem("zenelait-auth");
    if (raw) {
      try {
        const parsed = JSON.parse(raw);
        setAuth(parsed);
        setView(roleToView(parsed.role));
      } catch {
        localStorage.removeItem("zenelait-auth");
      }
    }
  }, []);

  const roleToView = (role) => {
    switch (role) {
      case "STUDENT":    return "student";
      case "TEACHER":    return "teacher";
      case "PARENT":     return "parent";
      case "ADMIN":      return "admin";
      case "SUPER_ADMIN":return "admin";
      default:           return "public";
    }
  };

  const handleLoginSuccess = (authResponse) => {
    setAuth(authResponse);
    localStorage.setItem("zenelait-auth", JSON.stringify(authResponse));
    setView(roleToView(authResponse.role));
  };

  const handleLogout = () => {
    setAuth(null);
    localStorage.removeItem("zenelait-auth");
    localStorage.removeItem("zenelait-student-profile");
    setView("login");
  };

  return (
    <>
      <GlobalStyle />

      {view === "public" && (
        <PublicWebsite onGoToLogin={() => setView("login")} />
      )}

      {view === "login" && (
        <LoginPage
          onLoginSuccess={handleLoginSuccess}
          onBack={() => setView("public")}
        />
      )}

      {/* Student — wrapped in StudentProfileProvider so profile persists across nav */}
      {view === "student" && (
        <StudentProfileProvider>
          <StudentDashboard onLogout={handleLogout} />
        </StudentProfileProvider>
      )}

      {view === "teacher" && <TeacherDashboard onLogout={handleLogout} />}

      {/* Admin — wrapped in AdminProfileProvider */}
      {view === "admin" && (
        <AdminProfileProvider>
          <AdminDashboard onLogout={handleLogout} />
        </AdminProfileProvider>
      )}

      {view === "parent" && <ParentDashboard onLogout={handleLogout} />}
    </>
  );
}
